import{_ as e,o as r,c as t,ae as i}from"./chunks/framework.MAq6t5g3.js";const p=JSON.parse('{"title":"はじめに","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),n={name:"guide/index.md"};function o(l,a,s,d,c,h){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="はじめに" tabindex="-1">はじめに <a class="header-anchor" href="#はじめに" aria-label="Permalink to &quot;はじめに&quot;">​</a></h1><p>RehearsalLinkを使った録音の解析から書き出しまでの基本フローをご紹介します。</p><h2 id="_1-録音をインポートする" tabindex="-1">1. 録音をインポートする <a class="header-anchor" href="#_1-録音をインポートする" aria-label="Permalink to &quot;1. 録音をインポートする&quot;">​</a></h2><p>iOSの「ファイル」アプリやボイスメモから、RehearsalLinkへ録音データを共有（インポート）します。</p><h2 id="_2-自動解析-セグメンテーション" tabindex="-1">2. 自動解析（セグメンテーション） <a class="header-anchor" href="#_2-自動解析-セグメンテーション" aria-label="Permalink to &quot;2. 自動解析（セグメンテーション）&quot;">​</a></h2><p>アプリが音声データを自動的に解析し、以下の3つに分類して波形を色分けします。</p><ul><li>🟦 <strong>演奏 (Performance)</strong>: 楽器の演奏箇所</li><li>🟩 <strong>会話 (Conversation)</strong>: 指導者やメンバーの指示・対話</li><li>⬜ <strong>無音 (Silence)</strong>: 休止時間</li></ul><h2 id="_3-文字起こし-transcription" tabindex="-1">3. 文字起こし (Transcription) <a class="header-anchor" href="#_3-文字起こし-transcription" aria-label="Permalink to &quot;3. 文字起こし (Transcription)&quot;">​</a></h2><p>「会話」セグメントを選択し、文字起こしを実行すると、会話の内容がテキスト化されます。 テキスト化されたセグメントは紫色で表示されます。</p><h2 id="_4-必要な音だけ書き出す" tabindex="-1">4. 必要な音だけ書き出す <a class="header-anchor" href="#_4-必要な音だけ書き出す" aria-label="Permalink to &quot;4. 必要な音だけ書き出す&quot;">​</a></h2><p>「演奏のみ」や「会話のみ」など、特定の種類のセグメントだけを繋ぎ合わせて新しい音声ファイルとしてエクスポートできます。 LINE等のメッセージアプリでの共有に便利です。</p>',11)])])}const u=e(n,[["render",o]]);export{p as __pageData,u as default};
